// Calculate arbitrage opportunities
const site1Odds = $input.first().json;
const site2Odds = $input.all()[1].json;

let arbitrageOpps = [];

for (let game of site1Odds.games) {
  const matchingGame = site2Odds.games.find(g => g.id === game.id);
  if (matchingGame) {
    const impliedProb1 = 1 / game.odds;
    const impliedProb2 = 1 / matchingGame.odds;
    const totalImplied = impliedProb1 + impliedProb2;

    if (totalImplied < 1) {
      const profit = ((1 / totalImplied) - 1) * 100;
      if (profit > 2) { // Only 2%+ arbitrage
        arbitrageOpps.push({
          game: game.name,
          profit: profit.toFixed(2),
          bet1: { site: 'Site1', odds: game.odds, stake: (impliedProb1 * 1000).toFixed(2) },
          bet2: { site: 'Site2', odds: matchingGame.odds, stake: (impliedProb2 * 1000).toFixed(2) }
        });
      }
    }
  }
}

return arbitrageOpps.map(opp => ({ json: opp }));

