const successProbability = Math.floor($json.marketDemand * 100) - 
                       ($json.offerStrategy === 'aggressive' ? 35 : 
                        $json.offerStrategy === 'moderate' ? 20 : 10);

return {
  json: {
    ...$json,
    successProbability: Math.max(5, successProbability),
    negotiationStage: 'Initial Offer',
    lastOffer: $json.lowballOffer,
    totalOpportunityValue: $json.opportunityValue
  }
};

const newOffer = Math.round($json.lastOffer * 0.85);
return {
  json: {
    ...$json,
    negotiationStage: 'Nuclear Offer',
    lastOffer: newOffer,
    totalOpportunityValue: $json.price - newOffer,
    successProbability: Math.min(90, $json.successProbability + 15)
  }
};

const totals = {
  totalOpportunityValue: items.reduce((sum, item) => sum + item.json.totalOpportunityValue, 0),
  averageDiscount: Math.round(items.reduce((sum, item) => sum + (item.json.totalOpportunityValue/item.json.price), 0) / items.length * 100),
  totalOffers: items.length
};

return [{
  json: totals
}];

const strategies = {
  'aggressive': 0.15,
  'moderate': 0.25,
  'soft': 0.35
};

const marketDemand = {
  'iPhone': 0.85,
  'Gaming': 0.65,
  'Macbook': 0.75,
  'RTX': 0.70,
  'Designer': 0.55
};

// Detect item type
let itemType = 'other';
Object.keys(marketDemand).forEach(key => {
  if ($json.title.includes(key)) itemType = key;
});

// Determine strategy based on demand
const strategy = marketDemand[itemType] > 0.7 ? 'aggressive' : 
               marketDemand[itemType] > 0.6 ? 'moderate' : 'soft';

const offer = Math.round($json.price * strategies[strategy]);

return {
  json: {
    ...$json,
    lowballOffer: offer,
    offerStrategy: strategy,
    marketDemand: marketDemand[itemType] || 0.5,
    opportunityValue: $json.price - offer
  }
};

return [{
  json: {
    report: `🔥 LOWBALL SUMMARY 🔥\n\n` +
           `💸 Total Opportunity Value: $${$json.totalOpportunityValue}\n` +
           `📉 Average Discount: ${$json.averageDiscount}%\n` +
           `📤 Offers Sent: ${$json.totalOffers}\n\n` +
           `💼 Best Deal: iPhone - $800 value\n` +
           `🤯 Most Aggressive: 85% off Gaming PC`
  }
}];

const excuses = [
  "My budget is only this after my dog's surgery",
  "This is all I have until payday next month",
  "I found one cheaper but prefer yours (just not the price)",
  "I'm a student with very limited funds",
  "I can pay cash today if you accept this"
];

return {
  json: {
    ...$json,
    message: `Hi ${$json.seller}! I'm very interested in your ${$json.title}. Would you consider $${$json.lowballOffer}? ${excuses[Math.floor(Math.random() * excuses.length)]}`
  }
};

// Filter items with valid pricing data
const items = $json["findItemsByKeywordsResponse"][0]["searchResult"][0]["item"] || [];

const deals = [];
for (const item of items) {
  try {
    const currentPrice = parseFloat(item["sellingStatus"][0]["currentPrice"][0]["__value__"]);
    const productValue = item["productId"] ? 
      parseFloat(item["productId"][0]["__value__"]) * 3 : // Placeholder logic
      currentPrice * 4; // Fallback

    if (productValue > currentPrice * 3) {
      deals.push({
        itemId: item["itemId"][0],
        title: item["title"][0],
        price: currentPrice,
        galleryURL: item["galleryURL"][0],
        productValue: productValue
      });
    }
  } catch (e) {}
}
return [{
  json: { deals }
}];

// Filter recent active discussions
const posts = $input.all().filter(post => {
  return post.created_time > new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()
});

return posts.map(post => ({
  post_id: post.id,
  topic: post.message,
  engagement: post.comments?.data?.length || 0
}));
